// ═══════════════════════════════════════════════════
// NODE 2: Parse Mensagem
// Extrai dados da mensagem recebida pela Evolution API
// Filtra mensagens enviadas pelo bot (fromMe)
// ═══════════════════════════════════════════════════

const body = $input.first().json;

// Suporta Evolution API v1 e v2
const data = body.data || body;
const key = data.key || {};

// Ignora mensagens enviadas pelo próprio bot
const fromMe = key.fromMe || data.fromMe || false;
if (fromMe) return [];

// Ignora mensagens de grupos
const remoteJid = key.remoteJid || data.remoteJid || '';
if (remoteJid.includes('@g.us')) return [];
if (!remoteJid) return [];

// Extrai número do telefone (somente dígitos)
const phone = remoteJid.replace('@s.whatsapp.net', '').replace(/\D/g, '');
if (!phone || phone.length < 8) return [];

// Extrai texto da mensagem (vários formatos)
const msg = data.message || {};
const text = (
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.imageMessage?.caption ||
  msg.videoMessage?.caption ||
  msg.documentMessage?.caption ||
  data.body ||
  ''
).trim();

if (!text) return [];

// Nome e instância
const pushName = data.pushName || data.pushname || 'Cliente';
const instanceName = body.instance || body.instanceName || $env.EVOLUTION_INSTANCE || '';

return [{
  json: {
    phone,
    name: pushName,
    message: text,
    remoteJid,
    instanceName,
    timestamp: Date.now()
  }
}];

// ═══════════════════════════════════════════════════
// NODE 3: DB - Cliente e Histórico
// Inicializa banco SQLite
// Busca ou cria registro do cliente
// Carrega histórico das últimas mensagens
// ═══════════════════════════════════════════════════

const Database = require('better-sqlite3');
const db = new Database('/data/bot.db');

// Cria tabelas se não existirem
db.exec(`
  CREATE TABLE IF NOT EXISTS clients (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    phone TEXT UNIQUE NOT NULL,
    name TEXT,
    service_interest TEXT,
    preferred_time TEXT,
    tag TEXT DEFAULT 'lead_frio',
    interaction_count INTEGER DEFAULT 0,
    transferred INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS conversations (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    phone TEXT NOT NULL,
    role TEXT NOT NULL,
    content TEXT NOT NULL,
    intent TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
  );
`);

const { phone, name } = $input.first().json;

// Busca cliente existente
let client = db.prepare('SELECT * FROM clients WHERE phone = ?').get(phone);

// Cria cliente novo se não existir
if (!client) {
  db.prepare('INSERT OR IGNORE INTO clients (phone, name) VALUES (?, ?)').run(phone, name);
  client = db.prepare('SELECT * FROM clients WHERE phone = ?').get(phone);
}

// Histórico das últimas 8 mensagens (4 trocas)
const history = db.prepare(
  'SELECT role, content FROM conversations WHERE phone = ? ORDER BY created_at DESC LIMIT 8'
).all(phone).reverse();

db.close();

return [{
  json: {
    ...$input.first().json,
    client,
    history,
    isNew: client.interaction_count === 0
  }
}];

// ═══════════════════════════════════════════════════
// NODE 4: Montar Payload IA
// Monta o array de mensagens para o Gemini
// Injeta contexto do cliente no system prompt
// ═══════════════════════════════════════════════════

const { phone, name, message, client, history } = $input.first().json;

const businessName = $env.BUSINESS_NAME || 'Nossa Empresa';

const systemPrompt = `Você é Ana, assistente virtual comercial da ${businessName}.
Seja amigável, profissional e concisa. Responda SEMPRE em português brasileiro.

DADOS DO CLIENTE:
- Nome: ${client?.name || name || 'Não informado'}
- Interesse: ${client?.service_interest || 'Ainda não coletado'}
- Status: ${client?.tag || 'lead_frio'}
- Total de interações: ${client?.interaction_count || 0}

SERVIÇOS OFERECIDOS:
- Compra e venda de veículos premium
- Avaliação de veículos usados
- Financiamento com as melhores taxas
- Blindagem veicular
- Revisão e manutenção especializada

INSTRUÇÕES:
1. Responda de forma natural e profissional
2. Use no máximo 3 frases curtas e diretas
3. Não use emojis em excesso (máximo 1)
4. Se não souber o nome, pergunte naturalmente
5. Se for orçamento, descubra o serviço específico
6. Se for agendamento, pergunte data e horário preferido
7. Se o cliente pedir humano ou reclamar → intent: humano

CLASSIFICAÇÃO DE LEADS:
- lead_frio: curiosidade, sem interesse real imediato
- lead_morno: demonstrou interesse, está pesquisando
- lead_quente: quer comprar/contratar, tem urgência

RETORNE APENAS JSON VÁLIDO (sem markdown):
{
  "intent": "duvida | orcamento | agendamento | humano",
  "reply": "texto da resposta ao cliente",
  "tag": "lead_frio | lead_morno | lead_quente",
  "extract": {
    "name": "nome mencionado ou null",
    "service": "serviço de interesse ou null",
    "datetime": "data/hora preferida ou null"
  }
}`;

const messages = [
  { role: 'system', content: systemPrompt },
  ...history.map(h => ({ role: h.role, content: h.content })),
  { role: 'user', content: message }
];

return [{
  json: {
    ...$input.first().json,
    openaiPayload: {
      model: 'gemini-2.0-flash',
      messages,
      temperature: 0.7,
      max_tokens: 600,
      response_format: { type: 'json_object' }
    }
  }
}];

// ═══════════════════════════════════════════════════
// NODE 6: Processar Resposta IA + Salvar no DB
// Parse do JSON retornado pelo OpenAI
// Salva conversa e atualiza dados do cliente
// Monta resposta final com formatação
// ═══════════════════════════════════════════════════

const Database = require('better-sqlite3');

// Pega contexto do node anterior ao OpenAI
const ctx = $('Montar Payload IA').first().json;
const aiRaw = $input.first().json;

const { phone, name, message, client } = ctx;

// Parse da resposta do OpenAI
let aiData;
try {
  const content = aiRaw.choices[0].message.content;
  aiData = JSON.parse(content);
  const validIntents = ['duvida', 'orcamento', 'agendamento', 'humano'];
  if (!validIntents.includes(aiData.intent)) aiData.intent = 'duvida';
  if (!['lead_frio', 'lead_morno', 'lead_quente'].includes(aiData.tag)) {
    aiData.tag = client?.tag || 'lead_frio';
  }
} catch (e) {
  // Fallback se parse falhar
  aiData = {
    intent: 'humano',
    reply: 'Vou te encaminhar para um de nossos atendentes. Um momento! 😊',
    tag: client?.tag || 'lead_frio',
    extract: {}
  };
}

// Monta resposta final (adiciona aviso de transferência se necessário)
let finalReply = aiData.reply || 'Estou aqui para ajudar! 😊';
if (aiData.intent === 'humano') {
  finalReply = `${finalReply}\n\n⏳ Você será atendido em breve.`;
}

// Salva no banco de dados
const db = new Database('/data/bot.db');

// Salva mensagem do usuário
db.prepare(
  'INSERT INTO conversations (phone, role, content, intent) VALUES (?, \'user\', ?, ?)'
).run(phone, message, aiData.intent);

// Salva resposta do bot
db.prepare(
  'INSERT INTO conversations (phone, role, content, intent) VALUES (?, \'assistant\', ?, ?)'
).run(phone, finalReply, aiData.intent);

// Atualiza dados do cliente
const extract = aiData.extract || {};
db.prepare(`
  UPDATE clients SET
    name = COALESCE(?, name),
    service_interest = COALESCE(?, service_interest),
    preferred_time = COALESCE(?, preferred_time),
    tag = ?,
    interaction_count = interaction_count + 1,
    transferred = CASE WHEN ? = 1 THEN 1 ELSE transferred END,
    updated_at = CURRENT_TIMESTAMP
  WHERE phone = ?
`).run(
  extract.name || null,
  extract.service || null,
  extract.datetime || null,
  aiData.tag,
  aiData.intent === 'humano' ? 1 : 0,
  phone
);

db.close();

// Monta notificação para atendente humano
const humanMsg = aiData.intent === 'humano'
  ? `🔔 *ATENDIMENTO SOLICITADO*\n\n` +
    `*Cliente:* ${extract.name || client?.name || name}\n` +
    `*Telefone:* ${phone}\n` +
    `*Interesse:* ${extract.service || client?.service_interest || 'Não informado'}\n` +
    `*Última mensagem:* "${message}"\n` +
    `*Tag:* ${aiData.tag}`
  : null;

return [{
  json: {
    phone,
    remoteJid: ctx.remoteJid,
    instanceName: ctx.instanceName,
    reply: finalReply,
    intent: aiData.intent,
    tag: aiData.tag,
    sendToHuman: aiData.intent === 'humano',
    humanPhone: $env.HUMAN_PHONE || '',
    humanMsg
  }
}];

// ═══════════════════════════════════════════════════
// NODE FALLBACK: Erro na IA
// Acionado quando o OpenAI retorna erro
// Monta resposta padrão de fallback
// ═══════════════════════════════════════════════════

const ctx = $('Montar Payload IA').first().json;

return [{
  json: {
    phone: ctx.phone,
    remoteJid: ctx.remoteJid,
    instanceName: ctx.instanceName,
    reply: 'Desculpe, tive um problema técnico. Vou te conectar com um atendente. 😊',
    intent: 'humano',
    tag: ctx.client?.tag || 'lead_frio',
    sendToHuman: false,
    humanMsg: null
  }
}];
